import { useState, useEffect } from "react";
import {
  Box,
  Typography,
  TextField,
  Button,
  Paper,
  Table,
  TableHead,
  TableRow,
  TableCell,
  TableBody,
  IconButton,
  Dialog,
  DialogTitle,
  DialogContent,
  DialogActions,
  Autocomplete,
  Chip,
  MenuItem,
} from "@mui/material";
import { Edit } from "@mui/icons-material";
import DeleteIcon from "@mui/icons-material/Delete";
import ManageAccountsIcon from "@mui/icons-material/ManageAccounts";
import API from "../../api/axios";

export default function ProjectManagement() {
  const [search, setSearch] = useState("");
  const [data, setData] = useState([]);
  const [users, setUsers] = useState([]);

  const [editOpen, setEditOpen] = useState(false);
  const [editData, setEditData] = useState(null);

  const [assignOpen, setAssignOpen] = useState(false);
  const [selectedProject, setSelectedProject] = useState(null);
  const [selectedUsers, setSelectedUsers] = useState([]);

  // 🔥 ROLE STATE
  const [roleOpen, setRoleOpen] = useState(false);
  const [selectedUser, setSelectedUser] = useState(null);
  const [newRole, setNewRole] = useState("");

  // 🔄 FETCH
  const fetchProjects = async () => {
    const res = await API.get("projects/");
    setData(res.data);
  };

  const fetchUsers = async () => {
    try {
      const res = await API.get("users/");
      setUsers(res.data);
    } catch {
      setUsers([]);
    }
  };

  useEffect(() => {
    fetchProjects();
    fetchUsers();
  }, []);

  // ✏️ UPDATE PROJECT
  const updateProject = async () => {
    await API.put(`projects/${editData.id}/`, editData);
    setEditOpen(false);
    fetchProjects();
  };

  // 🗑 DELETE PROJECT
  const deleteProject = async (id) => {
    if (!window.confirm("Delete project?")) return;
    await API.delete(`projects/${id}/delete/`);
    fetchProjects();
  };

  // ➕ ASSIGN USERS
  const assignUserToProject = async () => {
    await API.post("assign-user/", {
      project_id: selectedProject.id,
      user_ids: selectedUsers.map((u) => u.id),
    });

    setAssignOpen(false);
    setSelectedUsers([]);
    fetchProjects();
  };

  // ❌ REMOVE USER
  const removeUserFromProject = async (projectId, userId) => {
    await API.post("remove-user/", {
      project_id: projectId,
      user_id: userId,
    });

    fetchProjects();
  };

  // 🔥 UPDATE ROLE
  const updateUserRole = async () => {
    try {
      await API.put(`update-user-role/${selectedUser.id}/`, {
        sub_role: newRole,
      });

      setRoleOpen(false);
      setNewRole("");
      fetchProjects();

      alert("Role updated ✅");
    } catch (err) {
      console.error(err);
      alert("Error updating role ❌");
    }
  };

  return (
    <Box sx={{ p: 4, display: "flex", justifyContent: "center" }}>
      <Paper sx={{ width: "100%", maxWidth: 1200, p: 4, borderRadius: 4 }}>
        <Typography variant="h5" fontWeight="bold" mb={3}>
          Project Management
        </Typography>

        <TextField
          fullWidth
          placeholder="Search..."
          value={search}
          onChange={(e) => setSearch(e.target.value)}
          sx={{ mb: 3 }}
        />

        <Table>
          <TableHead>
            <TableRow>
              <TableCell>
                <b>Project</b>
              </TableCell>
              <TableCell>
                <b>Users</b>
              </TableCell>
              <TableCell>
                <b>Description</b>
              </TableCell>
              <TableCell>
                <b>Start</b>
              </TableCell>
              <TableCell>
                <b>End</b>
              </TableCell>
              <TableCell>
                <b>Actions</b>
              </TableCell>
            </TableRow>
          </TableHead>

          <TableBody>
            {data
              .filter((d) =>
                d.project_name?.toLowerCase().includes(search.toLowerCase()),
              )
              .map((row) => (
                <TableRow key={row.id}>
                  <TableCell>{row.project_name}</TableCell>

                  {/* USERS */}
                  <TableCell>
                    {row.users?.length > 0
                      ? row.users.map((u) => (
                          <Chip
                            key={u.id}
                            label={u.username}
                            onClick={() => {
                              setSelectedUser(u);
                              setRoleOpen(true);
                            }}
                            onDelete={() => {
                              if (window.confirm("Remove user?")) {
                                removeUserFromProject(row.id, u.id);
                              }
                            }}
                            sx={{ mr: 1, mb: 1 }}
                          />
                        ))
                      : "-"}
                  </TableCell>

                  <TableCell>{row.description}</TableCell>
                  <TableCell>{row.start}</TableCell>
                  <TableCell>{row.end}</TableCell>

                  {/* ACTIONS */}
                  <TableCell>
                    <IconButton
                      onClick={() => {
                        setEditData(row);
                        setEditOpen(true);
                      }}
                    >
                      <Edit />
                    </IconButton>

                    <IconButton
                      onClick={() => {
                        setSelectedProject(row);
                        setAssignOpen(true);
                      }}
                      sx={{ color: "#2e7d32" }}
                    >
                      ➕
                    </IconButton>

                    {/* 🔥 ROLE ICON */}
                    <IconButton
                      onClick={() => {
                        if (!row.users?.length) {
                          alert("No users");
                          return;
                        }
                        setSelectedUser(row.users[0]);
                        setRoleOpen(true);
                      }}
                      sx={{ color: "#ed6c02" }}
                    >
                      <ManageAccountsIcon />
                    </IconButton>

                    <IconButton onClick={() => deleteProject(row.id)}>
                      <DeleteIcon />
                    </IconButton>
                  </TableCell>
                </TableRow>
              ))}
          </TableBody>
        </Table>

        {/* EDIT */}
        <Dialog open={editOpen} onClose={() => setEditOpen(false)} fullWidth>
          <DialogTitle>Edit Project</DialogTitle>
          <DialogContent>
            <TextField
              fullWidth
              label="Project Name"
              value={editData?.project_name || ""}
              onChange={(e) =>
                setEditData({ ...editData, project_name: e.target.value })
              }
            />
          </DialogContent>
          <DialogActions>
            <Button onClick={() => setEditOpen(false)}>Cancel</Button>
            <Button onClick={updateProject}>Update</Button>
          </DialogActions>
        </Dialog>

        {/* ASSIGN */}
        <Dialog
          open={assignOpen}
          onClose={() => setAssignOpen(false)}
          fullWidth
        >
          <DialogTitle>Assign Users</DialogTitle>

          <DialogContent>
            <Typography mb={2}>
              Project: <b>{selectedProject?.project_name}</b>
            </Typography>

            <Autocomplete
              multiple
              options={users}
              getOptionLabel={(option) => option.username}
              value={selectedUsers}
              onChange={(e, val) => setSelectedUsers(val)}
              renderTags={(value, getTagProps) =>
                value.map((option, index) => (
                  <Chip
                    label={option.username}
                    {...getTagProps({ index })}
                    key={option.id}
                  />
                ))
              }
              renderInput={(params) => (
                <TextField {...params} label="Select Users" />
              )}
            />
          </DialogContent>

          <DialogActions>
            <Button onClick={() => setAssignOpen(false)}>Cancel</Button>
            <Button onClick={assignUserToProject}>Assign</Button>
          </DialogActions>
        </Dialog>

        {/* 🔥 ROLE CHANGE MODAL */}
        <Dialog open={roleOpen} onClose={() => setRoleOpen(false)} fullWidth>
          <DialogTitle>Change Role</DialogTitle>

          <DialogContent>
            <Typography mb={2}>
              User: <b>{selectedUser?.username}</b>
            </Typography>

            <TextField
              select
              fullWidth
              label="Select Role"
              value={newRole}
              onChange={(e) => setNewRole(e.target.value)}
            >
              <MenuItem value="project_manager">Project Manager</MenuItem>
              <MenuItem value="project_engineer">Project Engineer</MenuItem>
              <MenuItem value="data_contributor">Data Contributor</MenuItem>
            </TextField>
          </DialogContent>

          <DialogActions>
            <Button onClick={() => setRoleOpen(false)}>Cancel</Button>
            <Button onClick={updateUserRole} variant="contained">
              Update
            </Button>
          </DialogActions>
        </Dialog>
      </Paper>
    </Box>
  );
}
